on_write:
let res = #{ action: "Allow" };
if !payload.contains("block_hash") || !payload.contains("prev_hash") {
    res.action = "Reject";
    res.reason = "Ledger nodes must contain block_hash and prev_hash for cryptographic linkage";
}
res

on_read:
let res = #{ payload: payload };
if payload.block_hash == query_key || payload.prev_hash == query_key {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
